using Microsoft.AspNetCore.Mvc;
using AspNetEfCoreApi.Models;
using System;

namespace AspNetEfCoreApi.Controllers;

[ApiController]
[Route("api/[controller]")]
public class AuthController : ControllerBase
{
    [HttpPost("login")]
    public ActionResult<AuthResponse> Login(LoginRequest request)
    {
        // JWT generation omitted for brevity
        var token = Environment.GetEnvironmentVariable("JWT_SECRET") ?? "dev";
        return Ok(new AuthResponse { Token = token });
    }

    [HttpPost("register")]
    public ActionResult<User> Register(RegisterRequest request)
    {
        return Ok(new User { Email = request.Email });
    }
}

